  function t(locale, key, vars) {
    var bag = DICT[locale] || DICT.zh;
    var raw = bag[key] != null ? bag[key] : (DICT.zh[key] != null ? DICT.zh[key] : key);
    if (!vars) return raw;
    return raw.replace(/\{(\w+)\}/g, function (_, k) {
      return vars[k] != null ? String(vars[k]) : "";
    });
  }

  window.OpenAkita = window.OpenAkita || {};
  window.OpenAkita.i18n = { t: t, dict: DICT };
